var gameState = "play";
var score = 0;
var warningTimer = 0;
var gravity = 1.2;
var stage = 1;

var rocks = createGroup();
var boulders = createGroup();

var lebron = createSprite(200, 350);
lebron.setAnimation("lebron");
lebron.scale = 0.4;
lebron.setCollider("circle", 0, 0, 45);

function draw() {

 if (score < 500) {
   background("skyblue");
   stage = 1;
 } 
 else if (score < 1000) {
   background("orange");
   stage = 2;
 } 
 else {
   background("purple");
   stage = 3;
 }

 fill("green");
 rect(0, 380, 400, 20);

 if (gameState === "play") {

   if (keyDown("left") && lebron.x > 25) { 
     lebron.x -= 8; 
   }

   if (keyDown("right") && lebron.x < 375) { 
     lebron.x += 8; 
   }

   if (keyWentDown("space") && lebron.y >= 345) {
     lebron.velocityY = -18;
   }

   lebron.velocityY = lebron.velocityY + gravity;

   if (lebron.y > 350) {
     lebron.y = 350;
     lebron.velocityY = 0;
   }


   spawnEverything();

   if (lebron.isTouching(rocks) || lebron.isTouching(boulders)) {
     gameState = "lose";
   }


score++;

 } 
 else {
   showGameOver();
 }


 drawSprites();

 fill("black");
 textSize(20);
 text("Score: " + score, 20, 30);

 text("Stage: " + stage, 300, 30);
}

function spawnEverything() {

 if (frameCount % 45 === 0) {
   var r = createSprite(random(50, 350), -20);
   r.setAnimation("rock");
   r.velocityY = 6;
   r.lifetime = 100;
   r.setCollider("circle");
   rocks.add(r);
 }

 if (frameCount % 100 === 0) { 
   warningTimer = 30; 
 }

 if (warningTimer > 0) {

   warningTimer--;

   fill("red");
   textSize(30);
   text("⚠️", 370, 350);

   if (warningTimer === 1) {

     var b = createSprite(450, 360);
     b.setAnimation("boulder");

     b.scale = 0.5; 
     b.velocityX = -15; 
     b.lifetime = 50;

     b.setCollider("circle", 0, 0, 30);

     boulders.add(b);
   }
 }
}

function showGameOver() {

 fill("rgba(0,0,0,0.5)");
 rect(0,0,400,400);

fill("white");
 textAlign(CENTER);

 textSize(30);
 text("GAME OVER", 200, 200);

 textSize(18);
 text("Press 'R' to Restart", 200, 240);

 if (keyDown("r")) {
   resetGame();
 }
}



function resetGame() {

 rocks.destroyEach();
 boulders.destroyEach();

 lebron.y = 350;
 lebron.velocityY = 0;

 score = 0;
 gameState = "play";
}
